      "в Җв Җв Җв Җв Җв Җв ҖвЈ вЈҫв ҸвўҒв ”вўҒвЎҙвЈ«в һвЈЎв һв Ғв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв ҖвЎ”в №в Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җвў в Үв Җв Җв Җв Җв Җв Җв Җв Җв Җв ‘вЈ„в Җв Җв Җвў в Ҹв Җв Җв Җв Җв Җв Җв ҖвЈҮв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җ",
      "в Җв Җв Җв Җв ҖвЈ вЈҫв ҹвўҒвЎҙвўғвЈҙвЎ«в ҡвЈҒвЎҫв ғв Җв Җв Җв ҖвўҖвўҖвЎҖв Җв Җв Җв Җв Җв Җвўёв Җв ҳв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв ҖвўҖвЎҖв „в Ӯв Җв Җв ҖвўҖвЎҖв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв ҲвўҰвЎҖвЎ в Ӣв Җв Җв Җв Җв Җв Җв Җв ҖвўёвЎҖв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җ",
      "в Җв Җв Җвў вЎҫвЎҝвўғвЈҙв ӢвЈҙвЎҝв ӢвўҖвЈҙвЎҹв ҒвўҖв  в җв Җв Җв Җв Ҳв Үв ўв Җв Җв Җв Җв ҖвЎҺв Җвўҙв Җв Җв Җв Җв Җв Җв Җв ҖвўҖв ҙв ҠвўҖвЎҖв Өв җв Җв Ҳв „в ҳв ҷв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җвў»вЎҖв Җв Җв Җв Җв Җв Җв Җв Җв Җв ҖвЈҮв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җ",
      "в Җв ҖвЈ°вЎҹвЎқвўҖвўҫвўғвЈҫв Ӣв ҖвЈ вўҜв ҸвЎ в ’в Җв Җв Җв Җв Җв Җв Җв Җв “вЎҖвўҰвЎҖв Җв ҖвЎҮв Җвў°в Җв Җв Җв Җв Җв ҖвўҖвў”в Ўв җв Ӯв Җв ҖвЈ вЎ”в Ңв җв ’в Җвў’вЎҶв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв ҖвўҖвЈҖв ҳв Ғв ұвЎҫвЎҖв Җв Җв Җв Җв Җв Җв Җвў№в Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җ",
      "в ҖвЈ°вЎӢвЎҳвў вў«вўҸв һв ҒвўҖвЎјвЈЎв Ӣв Ҡв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв ұвЎ„в №в ҶвЈ°в Ғв Җв ҲвЈҮв Җв Җв Җв Җв Җв Ӣв Ғв Җв Җв Җв Җв Ҳв Ғв Җв Җв ҖвўҖвЎ в Ӣв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв ҖвЎёв ҒвЎҖвЎҖв Җв №вЎҷвЎ„в Җв Җв Җв Җв Җв Җвўёв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җ",
      "вў вЎҹвў°вў в ғвЈјв ғвЎҖвўҖвЎһвЈ°в ғв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв ёв Җв ҖвЎҖв Җв Җв Җв ҳвЎҶв Җв Җв Җв Җв ҖвЈ вЎ¶в Җв Җв Җв Җв Җв Җв ҖвЎҙв Ӣв Җв Җв Җв Җв Җв Җв Җв Җв Җв ҖвЈҝв Җв „вЎёв Ғв  в ҮвЎҮв Җв ҖвЎҮвўёв Җв Җв Җв Җв ҖвўҖвЎһв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җ",
      "вЈёв ғвЎӮвЎҺвЎҗвўҒвЎһвў в ҺвЈ°в ғв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җвўёв Җв Җв ҳвЎ„в Җв Җв ҖвЎҮв Җв ҖвўҖвЈҙв һв Ғв Җв Җв Җв Җв Җв ҖвЎ в Ҡв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җвў в ҸвЈҖвЎңв Җв ҖвЈҸвЎјв Җв ҖвўҖвЎҮв Ҳвўўв Җв Җв ҖвЈ в һв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җ",
      "вўҝвў вЈҝвЎ°вў в ҺвўҖвЎҸвЈ в ғв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җвўёв Җв Җв Җв ёвЎ„в ҖвЎңв Җв ҖвЈҙвўҹв Ғв Җв Җв Җв Җв Җв Җв ҖвўёвЎҒв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җвў°в Җв ҳв Җв Җв Җв ҹв Җв Җв ҖвўҲв Ғв  в Җв Ғв ҖвЎјв Ғв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җв Җ",
    }
    dashboard.section.header.val = logo
    local function getGreeting(name)
      local tableTime = os.date("*t")
      local hour = tableTime.hour
      local greetingsTable = {
        [1] = "пҲ¶  Sleep well",
        [2] = "оҚҢ  Good morning",
        [3] = "оҢҚ  Good afternoon",
        [4] = "оҚҚ  Good evening",
        [5] = "пӘ“ Good night",
      }
      local greetingIndex = 0
      if hour == 23 or hour < 7 then
        greetingIndex = 1
      elseif hour < 12 then
        greetingIndex = 2
      elseif hour >= 12 and hour < 18 then
        greetingIndex = 3
      elseif hour >= 18 and hour < 21 then
        greetingIndex = 4
      elseif hour >= 21 then
        greetingIndex = 5
      end
      return greetingsTable[greetingIndex] .. ", " .. name
    end
    local userName = "Han Yi"
    local greeting = getGreeting(userName)
    local greetHeading = {
      type = "text",
      val = greeting,
      opts = {
        position = "center",
        hl = "String",
      },
    }
    dashboard.section.buttons.val = {
      dashboard.button("f", "пңқ  Find file", ":Telescope find_files<CR>"),
      dashboard.button("t", "пһғ  Find text", ":Telescope live_grep <CR>"),
      dashboard.button("r", "пғ…  Recent files", ":Telescope oldfiles<CR>"),
      dashboard.button("q", "пҷҷ  Quit", ":qa<CR>"),
    }

    dashboard.config.layout = {
      { type = "padding", val = 2 },
      dashboard.section.header,
      { type = "padding", val = 2 },
      greetHeading,
      { type = "padding", val = 2 },
      dashboard.section.buttons,
      { type = "padding", val = 2 },
      dashboard.section.footer,
    }
    alpha.setup(dashboard.opts)

    vim.api.nvim_create_autocmd("User", {
      pattern = "LazyVimStarted",
      desc = "Update Alpha dashboard footer with plugin stats",
      once = true,
      callback = function()
        local stats = require("lazy").stats()
        local ms = math.floor(stats.startuptime * 100 + 0.5) / 100
        dashboard.section.footer.val = "Loaded " .. stats.loaded .. "/" .. stats.count .. " plugins in " .. ms .. "ms"
        pcall(vim.cmd.AlphaRedraw)
      end,
    })
  end
